def perceive(data):
    pairs = {}
    flat = []
    has_pair = False
    for line in str(data).replace(',', '\n').splitlines():
        line = line.strip()
        if not line:
            continue
        if ':' in line:
            has_pair = True
            h, _, p = line.partition(':')
            try:
                hi = int(float(h.strip()))
                pv = float(p.strip())
            except (ValueError, TypeError):
                continue
            if 0 <= hi < 24:
                pairs[hi] = pv
        else:
            try:
                flat.append(float(line))
            except (ValueError, TypeError):
                continue
    baseline = 0.10
    if has_pair:
        prices = [round(pairs.get(h, baseline), 6) for h in range(24)]
    elif flat:
        prices = [round(flat[h] if h < len(flat) else flat[-1], 6) for h in range(24)]
    else:
        prices = [baseline] * 24
    return {"prices": prices}
